     1→import express from "express";
     2→import cors from "cors";
     3→import { WebSocketServer, WebSocket } from "ws";
     4→import { createServer } from "http";
     5→import { execSync, exec as execCb } from "child_process";
     6→import { promisify } from "util";
     7→
     8→const exec = promisify(execCb);
     9→import { existsSync, mkdirSync } from "fs";
    10→import { basename, dirname, join, resolve } from "path";
    11→import { fileURLToPath } from "url";
    12→import { getDb } from "./db.js";
    13→import type { PrismaClient } from "../prisma/generated/client/index.js";
    14→import { indexAllCheckpointsV2, indexAllShadowBranches } from "./indexer.js";
    15→import { setupLogContentFts, syncLogContentFts, searchLogContent } from "./search.js";
    16→import { readConfig, addRepo, removeRepo, findRepo, defaultDbPath, type RepoConfig } from "./config.js";
    17→
    18→// ─── Schema push ──────────────────────────────────────────────────────────────
    19→
    20→const PROJECT_ROOT = resolve(dirname(fileURLToPath(import.meta.url)), "..");
    21→const PRISMA_BIN   = join(PROJECT_ROOT, "node_modules", ".bin", "prisma");
    22→
    23→async function pushSchema(dbFilePath: string): Promise<void> {
    24→  await exec(`${JSON.stringify(PRISMA_BIN)} db push`, {
    25→    env: { ...process.env, DATABASE_URL: `file:${dbFilePath}` },
    26→    cwd: PROJECT_ROOT,
    27→  });
    28→}
    29→
    30→// ─── Git user ─────────────────────────────────────────────────────────────────
    31→
    32→function gitConfigGet(key: string, cwd?: string): string | null {
    33→  try {
    34→    return execSync(`git config ${key}`, {
    35→      cwd,
    36→      encoding: "utf8",
    37→      stdio: ["ignore", "pipe", "ignore"],
    38→    }).trim() || null;
    39→  } catch { return null; }
    40→}
    41→
    42→function getGitUser(cwd?: string): { name: string | null; email: string | null } {
    43→  // Try local config first (cwd), then fall back to global
    44→  const name  = (cwd ? gitConfigGet("user.name", cwd)  : null) ?? gitConfigGet("--global user.name");
    45→  const email = (cwd ? gitConfigGet("user.email", cwd) : null) ?? gitConfigGet("--global user.email");
    46→  return { name, email };
    47→}
    48→
    49→// ─── Response types ───────────────────────────────────────────────────────────
    50→
    51→interface SessionResponse {
    52→  sessionId: string;
    53→  startedAt: string;
    54→  updatedAt: string;
    55→  cwd: string;
    56→  repoRoot: string | null;
    57→  repoName: string | null;
    58→  parentSessionId: string | null;
    59→  childSessionIds: string[];
    60→  gitUserName: string | null;
    61→  gitUserEmail: string | null;
    62→  prompt: string | null;
    63→  summary: string | null;
    64→  keywords: string[];
    65→  branch: string | null;
    66→  intent: string | null;
    67→  /** true when this session is currently indexed in a shadow branch */
    68→  isLive: boolean;
    69→}
    70→
    71→interface OverviewResponse {
    72→  sessionId: string;
    73→  summary: string;
    74→  keywords: string[];
    75→  startedAt: string;
    76→  endedAt: string;
    77→}
    78→
    79→// ─── Mapping helpers ──────────────────────────────────────────────────────────
    80→
    81→// ─── Multi-repo db lookup ─────────────────────────────────────────────────────
    82→
    83→/**
    84→ * Find the db and localPath for the repo that contains the given checkpointId.
    85→ * Tries the primary db first, then falls back through all configured repos.
    86→ */
    87→async function repoForCheckpoint(
    88→  primaryDb: PrismaClient,
    89→  primaryDbPath: string,
    90→  primaryLocalPath: string | undefined,
    91→  checkpointId: string,
    92→): Promise<{ db: PrismaClient; localPath: string | undefined }> {
    93→  const found = await primaryDb.checkpointMetadata.findUnique({ where: { checkpointId }, select: { id: true } });
    94→  if (found) return { db: primaryDb, localPath: primaryLocalPath };
    95→  for (const repo of readConfig().repos) {
    96→    if (repo.dbPath === primaryDbPath) continue;
    97→    try {
    98→      const repoDb = await getDb(repo.dbPath);
    99→      const hit = await repoDb.checkpointMetadata.findUnique({ where: { checkpointId }, select: { id: true } });
   100→      if (hit) return { db: repoDb, localPath: repo.localPath };
   101→    } catch { /* db may not exist yet */ }
   102→  }
   103→  return { db: primaryDb, localPath: primaryLocalPath }; // let the caller handle the 404
   104→}
