   106→// ─── Server ───────────────────────────────────────────────────────────────────
   107→
   108→export async function startServer(dbPath: string, port: number, repoDir?: string): Promise<void> {
   109→  // Strip CLAUDECODE so spawned sessions are not blocked by nested-session detection
   110→  delete process.env.CLAUDECODE;
   111→
   112→  const db = await getDb(dbPath);
   113→
   114→  // Ensure FTS table exists and is up-to-date on startup
   115→  await setupLogContentFts(db);
   116→  await syncLogContentFts(db);
   117→
   118→  const app = express();
   119→  app.use(cors());
   120→  app.use(express.json());
   121→
   122→  // Resolve git user and repo name from repo config once at startup
   123→  const gitUser  = getGitUser(repoDir);
   124→  const repoName = repoDir ? basename(repoDir) : null;
   125→
   126→  // GET /api/sessions — reconstructed from CheckpointSessionMetadata + ShadowSession
   127→  app.get("/api/sessions", async (_req, res) => {
   128→    try {
   129→      // Latest checkpoint meta per sessionId (asc order so map always ends on latest)
   130→      const allMetas = await db.checkpointSessionMetadata.findMany({
   131→        select: {
   132→          sessionId: true,
   133→          checkpointId: true,
   134→          branch: true,
   135→          summary: { select: { intent: true } },
   136→        },
   137→        orderBy: { createdAt: "asc" },
   138→      });
   139→      const cpMap = new Map<string, { branch: string | null; intent: string | null; checkpointId: string }>();
   140→      for (const m of allMetas) {
   141→        cpMap.set(m.sessionId, { branch: m.branch, intent: m.summary?.intent ?? null, checkpointId: m.checkpointId });
   142→      }
   143→
   144→      // Git user per checkpoint (from commit author stored at index time)
   145→      const allCheckpointIds = [...new Set(allMetas.map((m) => m.checkpointId))];
   146→      const cpUserRows = allCheckpointIds.length > 0
   147→        ? await db.checkpointMetadata.findMany({
   148→            where: { checkpointId: { in: allCheckpointIds } },
   149→            select: { checkpointId: true, gitUserName: true, gitUserEmail: true },
   150→          })
   151→        : [];
   152→      const cpUserMap = new Map(cpUserRows.map((r) => [r.checkpointId, r]));
   153→
   154→      const shadows = await db.shadowSession.findMany();
   155→      const shadowMap = new Map(shadows.map((s) => [s.sessionId, s]));
   156→
   157→      const allIds = [...new Set([...cpMap.keys(), ...shadows.map((s) => s.sessionId)])];
   158→      if (allIds.length === 0) {
   159→        res.json([]);
   160→        return;
   161→      }
   162→
   163→      // Min/max LogEvent timestamps per session
   164→      const times = await db.logEvent.groupBy({
   165→        by: ["sessionId"],
   166→        where: { sessionId: { in: allIds }, timestamp: { not: null } },
   167→        _min: { timestamp: true },
   168→        _max: { timestamp: true },
   169→      });
   170→      const timeMap = new Map(
   171→        times.map((r) => [r.sessionId!, { startedAt: r._min.timestamp, updatedAt: r._max.timestamp }])
   172→      );
   173→
   174→      // First cwd per session
   175→      const cwdRows = await db.logEvent.findMany({
   176→        where: { sessionId: { in: allIds }, cwd: { not: null } },
   177→        distinct: ["sessionId"],
   178→        orderBy: { id: "asc" },
   179→        select: { sessionId: true, cwd: true },
   180→      });
   181→      const cwdMap = new Map(cwdRows.map((e) => [e.sessionId!, e.cwd]));
   182→
   183→      const result: SessionResponse[] = allIds.map((sessionId) => {
   184→        const cp     = cpMap.get(sessionId) ?? null;
   185→        const shadow = shadowMap.get(sessionId) ?? null;
   186→        const t      = timeMap.get(sessionId);
   187→        const startedAt = t?.startedAt ?? shadow?.createdAt ?? null;
   188→        const updatedAt = t?.updatedAt ?? shadow?.createdAt ?? null;
   189→        const cpUser = cp ? cpUserMap.get(cp.checkpointId) ?? null : null;
   190→        return {
   191→          sessionId,
   192→          startedAt: startedAt?.toISOString() ?? new Date(0).toISOString(),
   193→          updatedAt: updatedAt?.toISOString() ?? new Date(0).toISOString(),
   194→          cwd:             cwdMap.get(sessionId) ?? shadow?.cwd ?? "",
   195→          repoRoot:        repoDir ?? null,
   196→          repoName:        repoName,
   197→          parentSessionId: null,
   198→          childSessionIds: [],
   199→          gitUserName:     cpUser?.gitUserName ?? gitUser.name,
   200→          gitUserEmail:    cpUser?.gitUserEmail ?? gitUser.email,
   201→          prompt:          shadow?.prompt ?? null,
   202→          summary:         null,
   203→          keywords:        [],
   204→          branch:          cp?.branch ?? shadow?.gitBranch ?? null,
   205→          intent:          cp?.intent ?? null,
   206→          isLive:          shadow !== null,
   207→        };
   208→      });
   209→
   210→      result.sort((a, b) => b.updatedAt.localeCompare(a.updatedAt));
   211→      res.json(result);
   212→    } catch (err) {
   213→      res.status(500).json({ error: String(err) });
   214→    }
   215→  });
   216→
   217→  // GET /api/sessions/:id
   218→  app.get("/api/sessions/:id", async (req, res) => {
   219→    try {
   220→      const id = req.params.id;
   221→      const [latestMeta, shadow, firstEvent, lastEvent] = await Promise.all([
   222→        db.checkpointSessionMetadata.findFirst({
   223→          where: { sessionId: id },
   224→          select: { branch: true, checkpointId: true, summary: { select: { intent: true } } },
   225→          orderBy: { createdAt: "desc" },
   226→        }),
   227→        db.shadowSession.findUnique({ where: { sessionId: id } }),
   228→        db.logEvent.findFirst({
   229→          where: { sessionId: id },
   230→          orderBy: { id: "asc" },
   231→          select: { cwd: true, timestamp: true },
   232→        }),
   233→        db.logEvent.findFirst({
   234→          where: { sessionId: id, timestamp: { not: null } },
   235→          orderBy: { id: "desc" },
   236→          select: { timestamp: true },
   237→        }),
   238→      ]);
   239→      if (!latestMeta && !shadow) {
   240→        res.status(404).json({ error: "Session not found" });
   241→        return;
   242→      }
   243→      const cpMeta = latestMeta
   244→        ? await db.checkpointMetadata.findUnique({
   245→            where: { checkpointId: latestMeta.checkpointId },
   246→            select: { gitUserName: true, gitUserEmail: true },
   247→          })
   248→        : null;
   249→      const startedAt = firstEvent?.timestamp ?? shadow?.createdAt ?? null;
   250→      const updatedAt = lastEvent?.timestamp  ?? shadow?.createdAt ?? null;
   251→      res.json({
   252→        sessionId:       id,
   253→        startedAt:       startedAt?.toISOString() ?? new Date(0).toISOString(),
   254→        updatedAt:       updatedAt?.toISOString() ?? new Date(0).toISOString(),
   255→        cwd:             firstEvent?.cwd ?? shadow?.cwd ?? "",
   256→        repoRoot:        repoDir ?? null,
   257→        repoName:        repoName,
   258→        parentSessionId: null,
   259→        childSessionIds: [],
   260→        gitUserName:     cpMeta?.gitUserName ?? gitUser.name,
   261→        gitUserEmail:    cpMeta?.gitUserEmail ?? gitUser.email,
   262→        prompt:          shadow?.prompt ?? null,
   263→        summary:         null,
   264→        keywords:        [],
   265→        branch:          latestMeta?.branch ?? shadow?.gitBranch ?? null,
   266→        intent:          latestMeta?.summary?.intent ?? null,
   267→        isLive:          shadow !== null,
   268→      } satisfies SessionResponse);
   269→    } catch (err) {
   270→      res.status(500).json({ error: String(err) });
   271→    }
   272→  });
