   362→  // ─── V2 helpers ─────────────────────────────────────────────────────────────
   363→
   364→  type V2Session = {
   365→    summary: {
   366→      intent: string; outcome: string;
   367→      openItems: { id: number; text: string; status: string; subSessionId: string | null }[];
   368→      frictionItems: { text: string }[];
   369→      repoLearnings: { text: string }[];
   370→      codeLearnings: { path: string; finding: string }[];
   371→      workflowLearnings: { text: string }[];
   372→    } | null;
   373→  };
   374→
   375→  function mapV2Summary(summary: NonNullable<V2Session["summary"]>) {
   376→    return {
   377→      intent:            summary.intent,
   378→      outcome:           summary.outcome,
   379→      openItems:         summary.openItems.map((r) => ({ id: r.id, text: r.text, status: r.status, subSessionId: r.subSessionId })),
   380→      friction:          summary.frictionItems.map((r) => r.text),
   381→      repoLearnings:     summary.repoLearnings.map((r) => r.text),
   382→      codeLearnings:     summary.codeLearnings.map((r) => ({ path: r.path, finding: r.finding })),
   383→      workflowLearnings: summary.workflowLearnings.map((r) => r.text),
   384→    };
   385→  }
   386→
   387→  const V2_SESSION_INCLUDE = {
   388→    summary: {
   389→      include: {
   390→        openItems:         true,
   391→        frictionItems:     true,
   392→        repoLearnings:     true,
   393→        codeLearnings:     true,
   394→        workflowLearnings: true,
   395→      },
   396→    },
   397→  } as const;
   398→
   399→  const V2_SESSION_ORDER = { createdAt: "desc" as const };
   400→
   401→  // GET /api/v2/checkpoints
   402→  app.get("/api/v2/checkpoints", async (_req, res) => {
   403→    try {
   404→      const checkpoints = await db.checkpointMetadata.findMany({
   405→        include: {
   406→          tokenUsage: true,
   407→          filesTouched: { include: { filePath: true } },
   408→        },
   409→      });
   410→
   411→      const checkpointIds = checkpoints.map((c) => c.checkpointId);
   412→
   413→      const sessions = await db.checkpointSessionMetadata.findMany({
   414→        where:   { checkpointId: { in: checkpointIds } },
   415→        orderBy: V2_SESSION_ORDER,
   416→        include: V2_SESSION_INCLUDE,
   417→      });
   418→
   419→      // Group sessions by checkpointId
   420→      const sessionsByCheckpoint = new Map<string, typeof sessions>();
   421→      for (const s of sessions) {
   422→        const arr = sessionsByCheckpoint.get(s.checkpointId) ?? [];
   423→        arr.push(s);
   424→        sessionsByCheckpoint.set(s.checkpointId, arr);
   425→      }
   426→
   427→      res.json(checkpoints.map((c) => {
   428→        const cpSessions = sessionsByCheckpoint.get(c.checkpointId) ?? [];
   429→        const summary = cpSessions.find((s) => s.summary)?.summary ?? null;
   430→        const latestCreatedAt = cpSessions
   431→          .filter((s): s is typeof s & { createdAt: Date } => s.createdAt !== null)
   432→          .map((s) => s.createdAt)
   433→          .sort((a, b) => b.getTime() - a.getTime())[0] ?? null;
   434→        return {
   435→          id:               c.id,
   436→          checkpointId:     c.checkpointId,
   437→          cliVersion:       c.cliVersion,
   438→          strategy:         c.strategy,
   439→          branch:           c.branch,
   440→          checkpointsCount: c.checkpointsCount,
   441→          createdAt:        latestCreatedAt?.toISOString() ?? null,
   442→          tokenUsage: c.tokenUsage ? {
   443→            inputTokens:         c.tokenUsage.inputTokens,
   444→            cacheCreationTokens: c.tokenUsage.cacheCreationTokens,
   445→            cacheReadTokens:     c.tokenUsage.cacheReadTokens,
   446→            outputTokens:        c.tokenUsage.outputTokens,
   447→            apiCallCount:        c.tokenUsage.apiCallCount,
   448→          } : null,
   449→          filesTouched:  c.filesTouched.map((f) => f.filePath.path),
   450→          sessionCount:  cpSessions.length,
   451→          summary: summary ? mapV2Summary(summary) : null,
   452→        };
   453→      }));
   454→    } catch (err) {
   455→      res.status(500).json({ error: String(err) });
   456→    }
   457→  });
