   583→  // GET /api/branch-log?localPath=<>&branch=<>
   584→  // Walks git log on the branch, parses "Entire-Checkpoint: <id>" trailers from
   585→  // commit bodies, and supplements with CheckpointIdGitOidJoin for indexed commits.
   586→  app.get("/api/branch-log", async (req, res) => {
   587→    try {
   588→      const localPath = typeof req.query.localPath === "string" ? req.query.localPath : null;
   589→      const branch    = typeof req.query.branch    === "string" ? req.query.branch    : null;
   590→      if (!localPath || !branch) {
   591→        res.status(400).json({ error: "localPath and branch are required" });
   592→        return;
   593→      }
   594→
   595→      const repo = findRepo(localPath);
   596→      if (!repo) { res.status(404).json({ error: "Repo not found in config" }); return; }
   597→
   598→      const repoDb = repo.dbPath === dbPath ? db : await getDb(repo.dbPath);
   599→
   600→      // Walk git log: parse "Entire-Checkpoint: <id>" from each commit body
   601→      const orderedIds: string[] = [];
   602→      const seenIds   = new Set<string>();
   603→      const allOids:   string[]  = [];
   604→
   605→      try {
   606→        // Use ASCII unit/record separators to safely delimit fields and commits
   607→        const { stdout: gitOut } = await exec(
   608→          `git -C ${JSON.stringify(localPath)} log --format=%H%x1f%B%x1e ${JSON.stringify(branch)}`,
   609→          { timeout: 10_000 },
   610→        );
   611→        for (const entry of gitOut.split("\x1e")) {
   612→          const sep = entry.indexOf("\x1f");
   613→          if (sep === -1) continue;
   614→          const oid  = entry.slice(0, sep).trim();
   615→          const body = entry.slice(sep + 1);
   616→          if (oid) allOids.push(oid);
   617→          const match = body.match(/^Entire-Checkpoint:\s*(\S+)$/m);
   618→          if (match) {
   619→            const id = match[1];
   620→            if (!seenIds.has(id)) { seenIds.add(id); orderedIds.push(id); }
   621→          }
   622→        }
   623→      } catch { /* git unavailable or branch not found — fall through to db */ }
   624→
   625→      // Supplement with CheckpointIdGitOidJoin for commits that are indexed
   626→      if (allOids.length > 0) {
   627→        const joins = await repoDb.checkpointIdGitOidJoin.findMany({
   628→          where: { gitOid: { in: allOids } },
   629→        });
   630→        for (const j of joins) {
   631→          if (!seenIds.has(j.checkpointId)) {
   632→            seenIds.add(j.checkpointId);
   633→            orderedIds.push(j.checkpointId);
   634→          }
   635→        }
   636→      }
   637→
   638→      // If git found nothing (no trailers, no OID matches), fall back to db branch field
   639→      const checkpointFilter = orderedIds.length > 0
   640→        ? { checkpointId: { in: orderedIds } }
   641→        : { branch };
   642→
   643→      const sessions = await repoDb.checkpointSessionMetadata.findMany({
   644→        where:   checkpointFilter,
   645→        orderBy: { createdAt: "desc" },
   646→        include: { ...V2_SESSION_INCLUDE, tokenUsage: true, filesTouched: { include: { filePath: true } } },
   647→      });
   648→
   649→      const sessionIds = [...new Set(sessions.map((s) => s.sessionId))];
   650→      // logEvents are always written to the primary db by the hook handler,
   651→      // even for repos that have their own separate checkpoint db.
   652→      const allLogEvents = await db.logEvent.findMany({
   653→        where:   { sessionId: { in: sessionIds } },
   654→        orderBy: { id: "asc" },
   655→        include: {
   656→          contents:    { orderBy: { contentIndex: "asc" } },
   657→          usage:       true,
   658→          hookProgress: true,
   659→          systemData:  true,
   660→        },
   661→      });
   662→
   663→      const logEventsBySession = new Map<string, typeof allLogEvents>();
   664→      for (const e of allLogEvents) {
   665→        if (!e.sessionId) continue;
   666→        const arr = logEventsBySession.get(e.sessionId) ?? [];
   667→        arr.push(e);
   668→        logEventsBySession.set(e.sessionId, arr);
   669→      }
   670→
   671→      // Sort by git log order when available, otherwise by createdAt (already ordered by db query)
   672→      const cpOrder = new Map(orderedIds.map((id, i) => [id, i]));
   673→      if (orderedIds.length > 0) {
   674→        sessions.sort((a, b) => (cpOrder.get(a.checkpointId) ?? 9999) - (cpOrder.get(b.checkpointId) ?? 9999));
   675→      }
   676→
   677→      const result = sessions
   678→        .map((s) => ({
   679→          checkpointId: s.checkpointId,
   680→          sessionId:    s.sessionId,
   681→          branch:       s.branch,
   682→          createdAt:    s.createdAt?.toISOString() ?? null,
   683→          filesTouched: s.filesTouched.map((f) => f.filePath.path),
   684→          tokenUsage:   s.tokenUsage ? {
   685→            inputTokens:         s.tokenUsage.inputTokens,
   686→            cacheCreationTokens: s.tokenUsage.cacheCreationTokens,
   687→            cacheReadTokens:     s.tokenUsage.cacheReadTokens,
   688→            outputTokens:        s.tokenUsage.outputTokens,
   689→            apiCallCount:        s.tokenUsage.apiCallCount,
   690→          } : null,
   691→          summary: s.summary ? mapV2Summary(s.summary) : null,
   692→          logEvents: (logEventsBySession.get(s.sessionId) ?? []).map((e) => ({
   693→            id:             e.id,
   694→            uuid:           e.uuid,
   695→            sessionId:      e.sessionId,
   696→            parentUuid:     e.parentUuid,
   697→            type:           e.type,
   698→            timestamp:      e.timestamp?.toISOString() ?? null,
   699→            cwd:            e.cwd,
   700→            gitBranch:      e.gitBranch,
   701→            slug:           e.slug,
   702→            isSidechain:    e.isSidechain,
   703→            toolUseId:      e.toolUseId,
   704→            parentToolUseId: e.parentToolUseId,
   705→            contents: e.contents.map((c) => ({
   706→              contentType:       c.contentType,
   707→              contentIndex:      c.contentIndex,
   708→              text:              c.text,
   709→              thinking:          c.thinking,
   710→              toolUseId:         c.toolUseId,
   711→              toolName:          c.toolName,
   712→              toolInput:         c.toolInput ? (JSON.parse(c.toolInput) as unknown) : null,
   713→              toolResultContent: c.toolResultContent,
   714→              isError:           c.isError,
   715→            })),
   716→            usage: e.usage ? {
   717→              model:                    e.usage.model,
   718→              stopReason:               e.usage.stopReason,
   719→              inputTokens:              e.usage.inputTokens,
   720→              outputTokens:             e.usage.outputTokens,
   721→              cacheCreationInputTokens: e.usage.cacheCreationInputTokens,
   722→              cacheReadInputTokens:     e.usage.cacheReadInputTokens,
   723→            } : null,
   724→            hookProgress: e.hookProgress ? {
   725→              type:      e.hookProgress.type,
   726→              hookEvent: e.hookProgress.hookEvent,
   727→              hookName:  e.hookProgress.hookName,
   728→              command:   e.hookProgress.command,
   729→            } : null,
   730→            systemData: e.systemData ? {
   731→              subtype:               e.systemData.subtype,
   732→              hookCount:             e.systemData.hookCount,
   733→              stopReason:            e.systemData.stopReason,
   734→              preventedContinuation: e.systemData.preventedContinuation,
   735→              level:                 e.systemData.level,
   736→              durationMs:            e.systemData.durationMs,
   737→            } : null,
   738→          })),
   739→        }));
   740→
   741→      res.json(result);
   742→    } catch (err) {
   743→      res.status(500).json({ error: String(err) });
   744→    }
   745→  });
