   771→  app.post("/api/sessions/spawn", async (req, res) => {
   772→    const { prompt, cwd, openItemIds, parentSessionId } = req.body as { prompt?: string; cwd?: string; openItemIds?: number[]; parentSessionId?: string };
   773→    if (!prompt || typeof prompt !== "string") {
   774→      res.status(400).json({ error: "prompt is required" });
   775→      return;
   776→    }
   777→    try {
   778→      const safeCwd = (cwd ?? process.env.HOME ?? "/tmp").replace(/'/g, "'\\''");
   779→      const safePrompt = prompt.replace(/'/g, "'\\''").replace(/\\/g, "\\\\").replace(/"/g, '\\"');
   780→      // Pass open item IDs and parent session so the SessionStart hook can link back
   781→      const envParts: string[] = [];
