  1038→  // ── Per-repo indexer helpers ───────────────────────────────────────────────
  1039→
  1040→  const CHECKPOINT_BRANCH = "entire/checkpoints/v1";
  1041→
  1042→  async function ensureWorktree(localPath: string): Promise<string> {
  1043→    const worktreePath = join(localPath, ".gossamer", "checkpoints");
  1044→    mkdirSync(join(localPath, ".gossamer"), { recursive: true });
  1045→    if (!existsSync(worktreePath)) {
  1046→      try {
  1047→        execSync(`git -C ${JSON.stringify(localPath)} worktree prune`, { stdio: "pipe" });
  1048→        execSync(
  1049→          `git -C ${JSON.stringify(localPath)} worktree add ${JSON.stringify(worktreePath)} ${CHECKPOINT_BRANCH}`,
  1050→          { stdio: "pipe" },
  1051→        );
  1052→        process.stderr.write(`checkpoint indexer: worktree created at ${worktreePath}\n`);
  1053→      } catch (err) {
  1054→        process.stderr.write(`checkpoint indexer: failed to create worktree for ${localPath} — ${err}\n`);
  1055→      }
  1056→    }
  1057→    return worktreePath;
  1058→  }
  1059→
  1060→  async function indexCheckpointsForRepo(name: string, localPath: string, repoDdPath: string): Promise<void> {
  1061→    process.stderr.write(`checkpoint indexer [${name}]: running\n`);
  1062→    try {
  1063→      const worktreePath = await ensureWorktree(localPath);
  1064→      if (!existsSync(worktreePath)) return;
  1065→      try {
  1066→        await exec(`git -C ${JSON.stringify(worktreePath)} fetch origin ${CHECKPOINT_BRANCH}`, { timeout: 10_000 });
  1067→      } catch { /* remote unavailable — index local state */ }
  1068→      try {
  1069→        await exec(`git -C ${JSON.stringify(worktreePath)} reset --hard refs/heads/${CHECKPOINT_BRANCH}`);
  1070→      } catch { /* non-fatal */ }
  1071→      const repoDb = await getDb(repoDdPath);
  1072→      const { checkpoints } = await indexAllCheckpointsV2(repoDb, worktreePath, undefined, localPath);
  1073→      if (checkpoints > 0) {
  1074→        process.stderr.write(`checkpoint indexer [${name}]: indexed ${checkpoints} new checkpoint(s)\n`);
  1075→        broadcast();
  1076→      } else {
