import React, { useEffect, useState } from "react";
import { useNavigate, useSearchParams } from "react-router-dom";
import { Center, Loader, Text, ScrollArea, Box } from "@mantine/core";
import { fetchBranchLog, type BranchLogEntry, type SessionCheckpoint } from "../api";
import { useBreadcrumb } from "../BreadcrumbContext";
import { EventItem } from "../components/EventItem";
import {
  logEventsToEvents,
  groupEvents,
  groupClaudeTurns,
  ClaudeTurnCard,
  CheckpointRow,
  type RenderItem,
} from "./SessionDetail";

function entryToCheckpoint(entry: BranchLogEntry): SessionCheckpoint {
  return {
    checkpointId: entry.checkpointId,
    branch:       entry.branch,
    cliVersion:   null,
    filesTouched: entry.filesTouched,
    tokenUsage:   entry.tokenUsage,
    createdAt:    entry.createdAt,
    summary:      entry.summary,
  };
}

export function BranchLog() {
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();
  const localPath = searchParams.get("localPath") ?? "";
  const branch    = searchParams.get("branch")    ?? "";
  const repoName  = searchParams.get("repoName")  ?? null;

  const [items, setItems] = useState<{ key: string; entry: BranchLogEntry; renderItems: RenderItem[] }[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError]     = useState<string | null>(null);
  const { setCrumbs } = useBreadcrumb();

  useEffect(() => {
    setCrumbs([
      ...(repoName ? [{ label: repoName }] : []),
      { label: branch },
    ]);
    fetchBranchLog(localPath, branch)
      .then((entries: BranchLogEntry[]) => {
        setItems(entries.map((entry) => ({
          key:         `${entry.checkpointId}-${entry.sessionId}`,
          entry,
          renderItems: groupClaudeTurns(groupEvents(logEventsToEvents(entry.logEvents))),
        })));
      })
      .catch((e: unknown) => setError(String(e)))
      .finally(() => setLoading(false));
  }, [localPath, branch]);

  if (loading) return <Center style={{ flex: 1 }}><Loader size="md" color="teal" /></Center>;
  if (error)   return <Center style={{ flex: 1 }}><Text c="red">{error}</Text></Center>;

  if (items.length === 0) {
    return (
      <Center style={{ flex: 1 }}>
        <Text c="dimmed" size="sm">No checkpoints found on branch <Text span ff="monospace">{branch}</Text>.</Text>
      </Center>
    );
  }

  return (
    <ScrollArea style={{ flex: 1 }}>
      <Box style={{ maxWidth: 860, margin: "0 auto", paddingBottom: 40 }}>
        {items.map(({ key, entry, renderItems }) => {
          const checkpoint = entryToCheckpoint(entry);
          return (
            <React.Fragment key={key}>
              <CheckpointRow
                checkpoint={checkpoint}
                localPath={localPath}
                onPress={() => navigate(`/checkpoints/${entry.checkpointId}`, {
                  state: { title: entry.branch ?? entry.checkpointId, localPath },
                })}
              />
              {renderItems.map((item, idx) => {
                const itemKey = item.kind === "claudeTurn"
                  ? `${key}-turn-${idx}`
                  : item.kind === "checkpoint"
                  ? `${key}-cp-${(item as { checkpoint: SessionCheckpoint }).checkpoint.checkpointId}`
                  : `${key}-evt-${(item as { event: { id: number } }).event.id}`;
                return (
                  <div key={itemKey}>
                    {item.kind === "claudeTurn" ? (
                      <ClaudeTurnCard toolGroups={item.toolGroups} stop={item.stop} />
                    ) : item.kind === "checkpoint" ? (
                      <CheckpointRow
                        checkpoint={(item as { checkpoint: SessionCheckpoint }).checkpoint}
                        localPath={localPath}
                        onPress={() => navigate(`/checkpoints/${(item as { checkpoint: SessionCheckpoint }).checkpoint.checkpointId}`, {
                          state: { title: (item as { checkpoint: SessionCheckpoint }).checkpoint.branch ?? (item as { checkpoint: SessionCheckpoint }).checkpoint.checkpointId, localPath },
                        })}
                      />
                    ) : (
                      <EventItem event={(item as { event: Parameters<typeof EventItem>[0]["event"] }).event} />
                    )}
                  </div>
                );
              })}
            </React.Fragment>
          );
        })}
      </Box>
    </ScrollArea>
  );
}

