content.content:
   118→  // GET /api/sessions — reconstructed from CheckpointSessionMetadata + ShadowSession
   119→  app.get("/api/sessions", async (_req, res) => {
   120→    try {
   121→      // Latest checkpoint meta per sessionId (asc order so map always ends on latest)
   122→      const allMetas = await db.checkpointSessionMetadata.findMany({
   123→        select: {
   124→          sessionId: true,
   125→          checkpointId: true,
   126→          branch: true,
   127→          summary: { select: { intent: true } },
   128→        },
   129→        orderBy: { createdAt: "asc" },
   130→      });
   131→      const cpMap = new Map<string, { branch: string | null; intent: string | null; checkpointId: string }>();
   132→      for (const m of allMetas) {
   133→        cpMap.set(m.sessionId, { branch: m.branch, intent: m.summary?.intent ?? null, checkpointId: m.checkpointId });
   134→      }
   135→
   136→      // Git user per checkpoint (from commit author stored at index time)
   137→      const allCheckpointIds = [...new Set(allMetas.map((m) => m.checkpointId))];
   138→      const cpUserRows = allCheckpointIds.length > 0
   139→        ? await db.checkpointMetadata.findMany({
   140→            where: { checkpointId: { in: allCheckpointIds } },
   141→            select: { checkpointId: true, gitUserName: true, gitUserEmail: true },
   142→          })
   143→        : [];
   144→      const cpUserMap = new Map(cpUserRows.map((r) => [r.checkpointId, r]));
   145→
   146→      const shadows = await db.shadowSession.findMany();
   147→      const shadowMap = new Map(shadows.map((s) => [s.sessionId, s]));
   148→
   149→      const allIds = [...new Set([...cpMap.keys(), ...shadows.map((s) => s.sessionId)])];
   150→      if (allIds.length === 0) {
   151→        res.json([]);
   152→        return;
   153→      }
   154→
   155→      // Min/max LogEvent timestamps per session
   156→      const times = await db.logEvent.groupBy({
   157→        by: ["sessionId"],
   158→        where: { sessionId: { in: allIds }, timestamp: { not: null } },
   159→        _min: { timestamp: true },
   160→        _max: { timestamp: true },
   161→      });
